import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"CI/CD 持续集成与交付","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/cicd.md","filePath":"deploy/cicd.md","lastUpdated":null}'),l={name:"deploy/cicd.md"};function t(o,a,c,d,p,r){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="ci-cd-持续集成与交付" tabindex="-1">CI/CD 持续集成与交付 <a class="header-anchor" href="#ci-cd-持续集成与交付" aria-label="Permalink to &quot;CI/CD 持续集成与交付&quot;">​</a></h1><p>CI/CD 负责编译、测试、构建镜像和自动发布，把代码从提交到上线的流程自动化。</p><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><ul><li>自动编译、测试、扫描、构建、部署。</li><li>减少手工发布的出错和耗时。</li><li>配合代码质量门禁，保证交付质量。</li></ul><h2 id="常见组件" tabindex="-1">常见组件 <a class="header-anchor" href="#常见组件" aria-label="Permalink to &quot;常见组件&quot;">​</a></h2><ul><li><code>Jenkins</code>：老牌 CI/CD 工具。</li><li><code>GitLab CI</code>：与 GitLab 集成的流水线。</li><li><code>GitHub Actions</code>：与 GitHub 集成的流水线。</li><li><code>Argo CD</code>：GitOps 部署。</li><li><code>Harbor</code>：镜像仓库。</li><li><code>Nexus</code> / <code>Artifactory</code>：Maven 私服 / 制品仓库。</li></ul><h2 id="典型发布链路" tabindex="-1">典型发布链路 <a class="header-anchor" href="#典型发布链路" aria-label="Permalink to &quot;典型发布链路&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提交代码</span></span>
<span class="line"><span>  -&gt; CI 拉取代码</span></span>
<span class="line"><span>  -&gt; 编译</span></span>
<span class="line"><span>  -&gt; 测试</span></span>
<span class="line"><span>  -&gt; 代码扫描</span></span>
<span class="line"><span>  -&gt; 构建镜像</span></span>
<span class="line"><span>  -&gt; 推送 Harbor</span></span>
<span class="line"><span>  -&gt; 部署 Kubernetes</span></span>
<span class="line"><span>  -&gt; 监控和告警</span></span></code></pre></div><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>用 GitLab 托管代码：优先 <code>GitLab CI</code>。</li><li>用 GitHub 托管代码：优先 <code>GitHub Actions</code>。</li><li>自建、需要复杂插件生态：<code>Jenkins</code>。</li><li>走 GitOps、声明式部署：<code>Argo CD</code>。</li></ul><p>镜像统一推送到 <code>Harbor</code>，Maven 制品统一走 <code>Nexus / Artifactory</code>。</p>`,11)])])}const b=e(l,[["render",t]]);export{u as __pageData,b as default};
